package main

import (
	"errors"
	"fmt"
)

type Account struct {
	Owner   string
	Balance float64
}

func (a *Account) Deposit(amount float64) error {
	if amount <= 0 {
		return errors.New("invalid deposit amount")
	}
	a.Balance += amount
	return nil
}

func (a *Account) Withdraw(amount float64) error {
	if amount <= 0 {
		return errors.New("invalid withdraw amount")
	}
	if amount > a.Balance {
		return errors.New("insufficient balance")
	}
	a.Balance -= amount
	return nil
}

func main() {
	acc := &Account{Owner: "小明", Balance: 1000}
	err := acc.Deposit(500)
	if err != nil {
		fmt.Printf("存款失败：%s\n", err.Error())
	} else {
		fmt.Printf("存款成功，余额：%.2f\n", acc.Balance)
	}
	err = acc.Withdraw(2000)
	if err != nil {
		fmt.Printf("取款失败：%s\n", err.Error())
	} else {
		fmt.Printf("取款成功，余额：%.2f\n", acc.Balance)
	}
	err = acc.Withdraw(300)
	if err != nil {
		fmt.Printf("取款失败：%s\n", err.Error())
	} else {
		fmt.Printf("取款成功，余额：%.2f\n", acc.Balance)
	}
	err = acc.Deposit(-100)
	if err != nil {
		fmt.Printf("存款失败：%s", err.Error())
	} else {
		fmt.Printf("存款成功，余额：%.2f", acc.Balance)
	}
}

